import React, { useCallback, useEffect, useMemo, useState } from 'react';
import api from '../utils/api';
import Sidebar from '../components/common/Sidebar';
import { DatePicker } from '../components/common/DatePicker';

const money = (value) => {
  const n = parseFloat(value);
  return Number.isFinite(n) ? `${n.toFixed(2)} €` : '0.00 €';
};

const percent = (value) => {
  const n = parseFloat(value);
  return Number.isFinite(n) ? `${n.toFixed(2)}%` : '0.00%';
};

const buildQuery = (filters) => {
  const qs = new URLSearchParams();
  Object.entries(filters).forEach(([key, value]) => {
    if (value !== '' && value !== null && value !== undefined) qs.set(key, value);
  });
  return qs.toString();
};

const currentYear = new Date().getFullYear();
const years = Array.from({ length: 8 }, (_, i) => currentYear - i);
const months = [
  ['1', 'January'], ['2', 'February'], ['3', 'March'], ['4', 'April'],
  ['5', 'May'], ['6', 'June'], ['7', 'July'], ['8', 'August'],
  ['9', 'September'], ['10', 'October'], ['11', 'November'], ['12', 'December'],
];

function KpiCard({ label, value, tone }) {
  return (
    <div className="card" style={{ padding: '1rem' }}>
      <div style={{ fontSize: '0.72rem', color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: '0.35rem' }}>{label}</div>
      <div style={{ fontSize: '1.35rem', fontWeight: 800, fontFamily: 'var(--font-heading)', color: tone || 'var(--text-primary)' }}>{value}</div>
    </div>
  );
}

function BreakdownSection({ title, rows }) {
  const max = Math.max(...rows.map(r => parseFloat(r.actualCostTotal || 0)), 1);
  return (
    <div className="card" style={{ padding: 0 }}>
      <div style={{ padding: '1rem', borderBottom: '1px solid var(--border)' }}>
        <h3 style={{ fontSize: '0.9rem', fontFamily: 'var(--font-heading)' }}>{title}</h3>
      </div>
      <div style={{ padding: '1rem', display: 'grid', gridTemplateColumns: '1fr 1.25fr', gap: '1rem' }}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
          {rows.length === 0 ? (
            <div style={{ color: 'var(--text-muted)', fontSize: '0.82rem' }}>No data</div>
          ) : rows.slice(0, 8).map(row => {
            const width = Math.max(4, (parseFloat(row.actualCostTotal || 0) / max) * 100);
            return (
              <div key={row.id || row.label}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.75rem', marginBottom: '0.2rem' }}>
                  <span style={{ color: 'var(--text-secondary)' }}>{row.label}</span>
                  <strong>{money(row.actualCostTotal)}</strong>
                </div>
                <div style={{ height: 8, background: 'var(--bg-hover)', borderRadius: 4, overflow: 'hidden' }}>
                  <div style={{ width: `${width}%`, height: '100%', background: row.variance >= 0 ? 'var(--red)' : 'var(--green)' }}/>
                </div>
              </div>
            );
          })}
        </div>
        <div style={{ overflowX: 'auto' }}>
          <table>
            <thead>
              <tr>
                <th>{title.replace('Cost per ', '')}</th>
                <th>Actual Cost Total</th>
                <th>Estimated Cost Total</th>
                <th>Variance</th>
              </tr>
            </thead>
            <tbody>
              {rows.map(row => (
                <tr key={row.id || row.label}>
                  <td style={{ fontWeight: 600 }}>{row.label}</td>
                  <td>{money(row.actualCostTotal)}</td>
                  <td>{money(row.estimatedCostTotal)}</td>
                  <td style={{ color: row.variance >= 0 ? 'var(--red)' : 'var(--green)', fontWeight: 700 }}>
                    {row.variance >= 0 ? '+' : ''}{money(row.variance)}
                  </td>
                </tr>
              ))}
              {rows.length === 0 && (
                <tr><td colSpan="4" style={{ color: 'var(--text-muted)' }}>No matching requests</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

export default function CostDashboardPage() {
  const [filters, setFilters] = useState({
    site_id: '',
    date_from: '',
    date_to: '',
    month: '',
    year: '',
    material_id: '',
    printer_id: '',
    technician_id: '',
  });
  const [options, setOptions] = useState({ sites: [], materials: [], printers: [], technicians: [] });
  const [summary, setSummary] = useState(null);
  const [breakdowns, setBreakdowns] = useState({ bySite: [], byMaterial: [], byPrinter: [], byTechnician: [] });
  const [loading, setLoading] = useState(true);
  const [exporting, setExporting] = useState(false);

  const query = useMemo(() => buildQuery(filters), [filters]);
  const setFilter = (key, value) => setFilters(prev => ({ ...prev, [key]: value }));

  useEffect(() => {
    const loadOptions = async () => {
      try {
        const [sites, materials, printers, users] = await Promise.all([
          api.get('/sites'),
          api.get('/materials'),
          api.get('/printers'),
          api.get('/users'),
        ]);
        setOptions({
          sites: sites.data,
          materials: materials.data,
          printers: printers.data,
          technicians: users.data.filter(u => u.role === 'technician'),
        });
      } catch (err) {
        console.error('[Cost Dashboard] Options failed:', err);
      }
    };
    loadOptions();
  }, []);

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const suffix = query ? `?${query}` : '';
      const [sum, site, material, printer, technician] = await Promise.all([
        api.get(`/dashboard/costs/summary${suffix}`),
        api.get(`/dashboard/costs/by-site${suffix}`),
        api.get(`/dashboard/costs/by-material${suffix}`),
        api.get(`/dashboard/costs/by-printer${suffix}`),
        api.get(`/dashboard/costs/by-technician${suffix}`),
      ]);
      setSummary(sum.data);
      setBreakdowns({
        bySite: site.data,
        byMaterial: material.data,
        byPrinter: printer.data,
        byTechnician: technician.data,
      });
    } catch (err) {
      console.error('[Cost Dashboard] Fetch failed:', err);
    } finally {
      setLoading(false);
    }
  }, [query]);

  useEffect(() => { fetchData(); }, [fetchData]);

  const downloadExport = async () => {
    setExporting(true);
    try {
      const suffix = query ? `?${query}` : '';
      const response = await api.get(`/export/cost-kpis${suffix}`, { responseType: 'blob' });
      const blob = new Blob([response.data], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.setAttribute('download', 'Cost KPI Report.xlsx');
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    } catch (err) {
      console.error('[Cost Dashboard] Export failed:', err);
      alert('Cost KPI export failed.');
    } finally {
      setExporting(false);
    }
  };

  const varianceTone = summary?.costVariance >= 0 ? 'var(--red)' : 'var(--green)';

  return (
    <div className="page">
      <Sidebar />
      <div className="main-content">
        <div className="page-header">
          <div>
            <h1 style={{ fontSize: '1.3rem', fontFamily: 'var(--font-heading)' }}>Cost KPI Dashboard</h1>
            <p style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: '0.2rem' }}>
              Estimated vs actual production costs, including cumulative reworks
            </p>
          </div>
          <button className="btn btn-primary btn-sm" onClick={downloadExport} disabled={exporting}>
            {exporting ? <span className="spinner" style={{ width: 14, height: 14 }}/> : null}
            Download Excel
          </button>
        </div>

        <div className="page-body">
          <div className="card" style={{ marginBottom: '1rem' }}>
            <div className="grid-2" style={{ gap: '0.85rem' }}>
              <div className="form-group">
                <label className="form-label">Site</label>
                <select className="form-select" value={filters.site_id} onChange={e => setFilter('site_id', e.target.value)}>
                  <option value="">All sites</option>
                  {options.sites.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Material</label>
                <select className="form-select" value={filters.material_id} onChange={e => setFilter('material_id', e.target.value)}>
                  <option value="">All materials</option>
                  {options.materials.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Printer</label>
                <select className="form-select" value={filters.printer_id} onChange={e => setFilter('printer_id', e.target.value)}>
                  <option value="">All printers</option>
                  {options.printers.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Technician</label>
                <select className="form-select" value={filters.technician_id} onChange={e => setFilter('technician_id', e.target.value)}>
                  <option value="">All technicians</option>
                  {options.technicians.map(t => <option key={t.id} value={t.id}>{t.first_name} {t.last_name}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Date Start</label>
                <DatePicker value={filters.date_from} onChange={v => setFilter('date_from', v)} placeholder="Start date"/>
              </div>
              <div className="form-group">
                <label className="form-label">Date End</label>
                <DatePicker value={filters.date_to} onChange={v => setFilter('date_to', v)} placeholder="End date"/>
              </div>
              <div className="form-group">
                <label className="form-label">Month</label>
                <select className="form-select" value={filters.month} onChange={e => setFilter('month', e.target.value)}>
                  <option value="">All months</option>
                  {months.map(([value, label]) => <option key={value} value={value}>{label}</option>)}
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Year</label>
                <select className="form-select" value={filters.year} onChange={e => setFilter('year', e.target.value)}>
                  <option value="">All years</option>
                  {years.map(y => <option key={y} value={y}>{y}</option>)}
                </select>
              </div>
            </div>
          </div>

          {loading ? (
            <div style={{ display: 'flex', justifyContent: 'center', padding: '3rem' }}>
              <span className="spinner" style={{ width: 30, height: 30 }}/>
            </div>
          ) : (
            <>
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(5, minmax(0, 1fr))', gap: '1rem', marginBottom: '1rem' }}>
                <KpiCard label="Estimated Cost Total" value={money(summary?.estimatedCostTotal)} />
                <KpiCard label="Actual Cost Total" value={money(summary?.actualCostTotal)} />
                <KpiCard label="Cost Variance" value={`${summary?.costVariance >= 0 ? '+' : ''}${money(summary?.costVariance)}`} tone={varianceTone} />
                <KpiCard label="Cost Variance %" value={percent(summary?.costVariancePercent)} tone={varianceTone} />
                <KpiCard label="Avg Cost / Request" value={money(summary?.averageCostPerRequest)} />
              </div>

              <div className="card" style={{ marginBottom: '1rem', display: 'flex', gap: '1.5rem', flexWrap: 'wrap', color: 'var(--text-secondary)', fontSize: '0.82rem' }}>
                <span>Last updated: <strong style={{ color: 'var(--text-primary)' }}>{summary?.lastUpdated ? new Date(summary.lastUpdated).toLocaleString('fr-FR') : '-'}</strong></span>
                <span>Requests analyzed: <strong style={{ color: 'var(--text-primary)' }}>{summary?.requestCount || 0}</strong></span>
                <span>Reworks included: <strong style={{ color: 'var(--text-primary)' }}>{summary?.reworkCount || 0}</strong></span>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <BreakdownSection title="Cost per Site" rows={breakdowns.bySite} />
                <BreakdownSection title="Cost per Material" rows={breakdowns.byMaterial} />
                <BreakdownSection title="Cost per Printer" rows={breakdowns.byPrinter} />
                <BreakdownSection title="Cost per Technician" rows={breakdowns.byTechnician} />
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
